SELECT 'system', 'email', 'Cancellation Confirmation (T1)', 'Confirms subscription cancellation and opens the 12-month read-only retention lifecycle; verbatim retention citations.', 'subscriptions', 'correspondence', 'subscription.cancellation_confirm',
  'Your Pleks subscription has been cancelled', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{cancelledDate}}', '{{cancellationMethod}}', '{{purgeEligibleAt}}', '{{daysUntilPurge}}', '{{exportUrl}}', '{{reactivateUrl}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"heading","text":"Subscription cancelled — your data is available until {{purgeEligibleAt}}"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"Your **{{branding.orgName}}** subscription was cancelled on {{cancelledDate}}. We confirmed this cancellation via {{cancellationMethod}}."},{"type":"paragraph","text":"By confirming cancellation, you instructed Pleks to begin the account closure and data-retention lifecycle described in Section 04 of our Terms of Service in force at the time of your cancellation. The 12-month read-only access period begins now."},{"type":"heading","text":"What happens to your data"},{"type":"paragraph","text":"**Operational data** — properties, leases, communications, tenant profiles, and historical records of day-to-day platform use — remains fully readable and exportable until {{purgeEligibleAt}}. That''s 12 months from {{cancelledDate}} ({{daysUntilPurge}} days). After that date, Operational data is deleted from production systems and excluded from backup retention thereafter."},{"type":"paragraph","text":"**Compliance Records** — a small set of records we are legally required to retain — will not be deleted on {{purgeEligibleAt}}. These include:"},{"type":"list","items":["Tax and billing records (5 years, Tax Administration Act s29)","Trust account records (5 years from end of financial year, Property Practitioners Act Regulation 33)","FICA verification records (5 years, Financial Intelligence Centre Act s23)","Audit and consent logs (7–10 years, POPIA s17 documentation)","Accounting records (7 years, Companies Act s24)","Records subject to any active legal hold or dispute"]},{"type":"paragraph","text":"These Compliance Records remain in a restricted-access archive for the periods specified above. The full retention schedule is published in our Privacy Policy."},{"type":"paragraph","text":"Where retention is required by law, regulatory request, or active dispute, the deletion of Operational data may also be deferred — we will notify you separately if this applies."},{"type":"heading","text":"What you should do"},{"type":"paragraph","text":"As the Responsible Party for your tenants'' personal information under POPIA, your obligations to those tenants continue after this cancellation. Trust account records carry a 5-year statutory retention requirement under the Property Practitioners Act. Please export and securely store all records you may need for these obligations before {{purgeEligibleAt}}."},{"type":"cta","label":"Export all data","href":"{{exportUrl}}"},{"type":"cta","label":"Reactivate","href":"{{reactivateUrl}}"},{"type":"paragraph","text":"Exports are provided as a downloadable archive at the time of request. You are responsible for verifying that exported records are complete before the deletion date. Pleks does not warrant the long-term integrity of exported files held outside the platform."},{"type":"heading","text":"Reactivation"},{"type":"paragraph","text":"You can reactivate your account at any time before {{purgeEligibleAt}} and your Operational data will be restored in place — leases, tenants, documents and history. The Terms of Service and pricing in force at the time of reactivation will apply."},{"type":"paragraph","text":"All deletion lifecycle dates are calculated in South Africa Standard Time (SAST, UTC+2). Scheduled purge jobs may execute within a 24-hour window of the deletion date."},{"type":"paragraph","text":"You may request deletion or destruction of personal information under POPIA s24–s25, subject to applicable legal retention obligations. You may also request a copy of your data under s23, or lodge a complaint with the Information Regulator (South Africa) under POPIA s74 — see our Privacy Policy."}]'::jsonb, NULL
WHERE NOT EXISTS (
  SELECT 1 FROM document_templates WHERE scope='system' AND template_key='subscription.cancellation_confirm' AND template_type='email'
);

INSERT INTO document_templates (
  scope, template_type, name, description, category, comms_class, template_key,
  subject, merge_fields, version, legal_review_ref, is_deletable, body_blocks, body_variants
