SELECT 'system', 'email', 'Cancellation 90-Day Warning (T2)', '90-day reminder before cancelled account''s Operational data is deleted from production; verbatim retention citations.', 'subscriptions', 'correspondence', 'subscription.cancellation_warn_90',
  '90 days until your Pleks data is scheduled for deletion', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{cancelledDate}}', '{{purgeEligibleAt}}', '{{exportUrl}}', '{{reactivateUrl}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"heading","text":"90 days until production deletion"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"This is a reminder that the **{{branding.orgName}}** account was cancelled on {{cancelledDate}}."},{"type":"paragraph","text":"Your Operational data — properties, leases, communications, tenant profiles, and historical records — is scheduled for deletion from production systems on {{purgeEligibleAt}}, 90 days from today. After that date, Operational data will be excluded from backup retention."},{"type":"heading","text":"What you should do"},{"type":"paragraph","text":"If you want to keep any Operational records, export them now. You are responsible for verifying that exported records are complete before the deletion date."},{"type":"cta","label":"Export all data now","href":"{{exportUrl}}"},{"type":"cta","label":"Reactivate account","href":"{{reactivateUrl}}"},{"type":"paragraph","text":"If you''d like to continue using Pleks, you can reactivate before {{purgeEligibleAt}} — the Terms of Service and pricing in force at the time of reactivation will apply."},{"type":"paragraph","text":"As the Responsible Party for your tenants'' personal information under POPIA, your obligations to those tenants continue after the deletion. If you require historical lease, payment, or trust records to meet those obligations, export them before {{purgeEligibleAt}}."},{"type":"paragraph","text":"A small set of Compliance Records — tax, trust, FICA, audit, and accounting records — are retained in a restricted-access archive for between 5 and 10 years depending on the record type, as set out in our Privacy Policy."},{"type":"paragraph","text":"Deletion dates are calculated in South Africa Standard Time (SAST). Cancellation lifecycle: see Section 04 of our Terms of Service."},{"type":"paragraph","text":"You may request deletion or destruction of personal information under POPIA s24–s25, subject to applicable legal retention obligations. You may also request a copy of your data under s23, or lodge a complaint with the Information Regulator (South Africa) under POPIA s74 — see our Privacy Policy."}]'::jsonb, NULL
WHERE NOT EXISTS (
  SELECT 1 FROM document_templates WHERE scope='system' AND template_key='subscription.cancellation_warn_90' AND template_type='email'
);

