SELECT 'system', 'email', 'Cancellation 30-Day Warning (T3)', 'Final-month reminder — 30 days until cancelled account''s Operational data is deleted; verbatim retention citations.', 'subscriptions', 'correspondence', 'subscription.cancellation_warn_30',
  '30 days until your Pleks data is scheduled for deletion', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{cancelledDate}}', '{{purgeEligibleAt}}', '{{exportUrl}}', '{{reactivateUrl}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"heading","text":"Final month — 30 days to deletion"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"The **{{branding.orgName}}** account was cancelled on {{cancelledDate}}, and your Operational data is now scheduled for deletion in 30 days — on {{purgeEligibleAt}}."},{"type":"paragraph","text":"After that date, your Operational records — properties, leases, communications, tenant profiles, and historical activity — will be deleted from production systems and excluded from backup retention."},{"type":"heading","text":"Last month for export or reactivation"},{"type":"cta","label":"Export all data now","href":"{{exportUrl}}"},{"type":"cta","label":"Reactivate account","href":"{{reactivateUrl}}"},{"type":"paragraph","text":"You are responsible for verifying that exported records are complete before the deletion date."},{"type":"paragraph","text":"If you''d like to continue using Pleks, reactivate before {{purgeEligibleAt}} — the Terms of Service and pricing in force at the time of reactivation will apply."},{"type":"paragraph","text":"If you have continuing POPIA, RHA, or PPA obligations to your tenants — including the 5-year trust-record retention — export the records you need before deletion."},{"type":"paragraph","text":"A small set of Compliance Records — tax, trust, FICA, audit, and accounting records — are retained in a restricted-access archive for between 5 and 10 years depending on the record type, as set out in our Privacy Policy."},{"type":"paragraph","text":"All deletion lifecycle dates are calculated in South Africa Standard Time (SAST). Cancellation lifecycle: see Section 04 of our Terms of Service."},{"type":"paragraph","text":"You may request deletion or destruction of personal information under POPIA s24–s25, subject to applicable legal retention obligations. You may also request a copy of your data under s23, or lodge a complaint with the Information Regulator (South Africa) under POPIA s74 — see our Privacy Policy."}]'::jsonb, NULL
WHERE NOT EXISTS (
  SELECT 1 FROM document_templates WHERE scope='system' AND template_key='subscription.cancellation_warn_30' AND template_type='email'
);

