SELECT 'system', 'email', 'Cancellation 7-Day Warning (T4)', 'Final-week reminder — 7 days until cancelled account''s Operational data is deleted; verbatim retention citations.', 'subscriptions', 'correspondence', 'subscription.cancellation_warn_7',
  '7 days until your Pleks data is deleted', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{purgeEligibleAt}}', '{{exportUrl}}', '{{reactivateUrl}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"callout","tone":"warn","text":"⚠ One week to data deletion"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"This is a final-week reminder. The **{{branding.orgName}}** account is scheduled for Operational data deletion on {{purgeEligibleAt}} — 7 days from today."},{"type":"paragraph","text":"All properties, leases, communications, tenant profiles, and historical records will be deleted from production systems and excluded from backup retention."},{"type":"heading","text":"Last chance to export or reactivate"},{"type":"cta","label":"Export all data now","href":"{{exportUrl}}"},{"type":"cta","label":"Reactivate account","href":"{{reactivateUrl}}"},{"type":"paragraph","text":"You are responsible for verifying that exported records are complete before the deletion date. If anything is missing or unreadable, contact support@pleks.co.za this week — after {{purgeEligibleAt}}, Operational records will no longer be recoverable through Pleks production systems once the backup-retention window expires."},{"type":"paragraph","text":"If you''d like to continue using Pleks, reactivate before {{purgeEligibleAt}} — the Terms of Service and pricing in force at the time of reactivation will apply."},{"type":"paragraph","text":"A small set of Compliance Records — tax, trust, FICA, audit, and accounting records — are retained in a restricted-access archive for between 5 and 10 years depending on the record type, as set out in our Privacy Policy."},{"type":"paragraph","text":"Deletion lifecycle calculated in South Africa Standard Time (SAST)."},{"type":"paragraph","text":"You may request deletion or destruction of personal information under POPIA s24–s25, subject to applicable legal retention obligations. You may also request a copy of your data under s23, or lodge a complaint with the Information Regulator (South Africa) under POPIA s74 — see our Privacy Policy."}]'::jsonb, NULL
WHERE NOT EXISTS (
  SELECT 1 FROM document_templates WHERE scope='system' AND template_key='subscription.cancellation_warn_7' AND template_type='email'
);

