SELECT 'system', 'email', 'Cancellation Final 24-Hour Warning (T5)', 'Final 24-hour notice before cancelled account''s Operational data is deleted tomorrow; verbatim retention citations.', 'subscriptions', 'correspondence', 'subscription.cancellation_warn_24h',
  'Final notice: your Pleks data is deleted tomorrow', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{purgeEligibleAt}}', '{{exportUrl}}', '{{reactivateUrl}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"callout","tone":"warn","text":"⚠ Operational data deletion is tomorrow"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"Tomorrow — {{purgeEligibleAt}} — is the scheduled production-deletion date for **{{branding.orgName}}**. After this date, Operational data will no longer be recoverable through Pleks production systems once the backup-retention window expires."},{"type":"paragraph","text":"All properties, leases, communications, tenant profiles, and historical records will be deleted from production systems and excluded from backup retention."},{"type":"cta","label":"Export all data now","href":"{{exportUrl}}"},{"type":"cta","label":"Reactivate account","href":"{{reactivateUrl}}"},{"type":"paragraph","text":"You are responsible for verifying that exported records are complete before deletion. The deletion job runs in South Africa Standard Time and may execute within a 24-hour window of {{purgeEligibleAt}}."},{"type":"paragraph","text":"If you''d like to keep your account, reactivate before 23:59 SAST tonight — the Terms of Service and pricing in force at the time of reactivation will apply."},{"type":"paragraph","text":"A small set of Compliance Records — tax, trust, FICA, audit, and accounting records — are retained in a restricted-access archive for between 5 and 10 years depending on the record type, as set out in our Privacy Policy."},{"type":"paragraph","text":"All deletion lifecycle dates are calculated in South Africa Standard Time (SAST, UTC+2). Cancellation lifecycle: Section 04 of our Terms of Service in force at the time of your cancellation."},{"type":"paragraph","text":"You may request deletion or destruction of personal information under POPIA s24–s25, subject to applicable legal retention obligations. You may also request a copy of your data under s23, or lodge a complaint with the Information Regulator (South Africa) under POPIA s74 — see our Privacy Policy."}]'::jsonb, NULL
