SELECT 'system', 'email', 'Account Closed (T6)', 'Post-deletion confirmation — Operational data deleted, Compliance Records retained; verbatim retention citations + final billing.', 'subscriptions', 'correspondence', 'subscription.account_closed',
  'Your Pleks account has been closed', ARRAY['{{recipient.salutation}}', '{{branding.orgName}}', '{{recipientEmail}}', '{{cancelledDate}}', '{{purgedDate}}', '{{finalInvoiceDate}}'], 1, 'ADDENDUM_70C §8.8', false,
  '[{"type":"heading","text":"Account closed"},{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"paragraph","text":"The **{{branding.orgName}}** account ({{recipientEmail}}), cancelled on {{cancelledDate}}, was closed on {{purgedDate}}."},{"type":"heading","text":"What was deleted"},{"type":"paragraph","text":"Operational data — properties, leases, communications, tenant profiles, and historical records of day-to-day platform use — has been deleted from production systems and excluded from backup retention thereafter."},{"type":"heading","text":"What is retained"},{"type":"paragraph","text":"The following Compliance Records remain in a restricted-access archive for the periods specified, as set out in our Privacy Policy:"},{"type":"list","items":["Tax and billing records (5 years, Tax Administration Act s29)","Trust account records (5 years from end of financial year, Property Practitioners Act Regulation 33)","FICA verification records (5 years, Financial Intelligence Centre Act s23)","Audit and consent logs (7–10 years, POPIA s17 documentation)","Accounting records (7 years, Companies Act s24)","Records subject to any active legal hold or dispute"]},{"type":"paragraph","text":"These records are accessed only for the legal obligation that requires their retention, and are deleted at the end of the applicable retention window."},{"type":"heading","text":"Final billing"},{"type":"paragraph","text":"The final invoice for **{{branding.orgName}}** was issued on {{finalInvoiceDate}}. No further charges will be made to your payment method."},{"type":"heading","text":"If you believe this is in error"},{"type":"paragraph","text":"If you believe this account closure was made in error, or if you need to access your retained Compliance Records, contact us at support@pleks.co.za. Pleks retains a documented record of all cancellation and deletion events for accountability purposes under POPIA s17."},{"type":"paragraph","text":"Deletion lifecycle dates are calculated in South Africa Standard Time (SAST, UTC+2)."},{"type":"paragraph","text":"This account no longer exists as an active production account. Compliance Records are retained per the schedule above and our Privacy Policy. You may at any time lodge a complaint about data handling with the Information Regulator (South Africa) under POPIA s74."}]'::jsonb, NULL
WHERE NOT EXISTS (
  SELECT 1 FROM document_templates WHERE scope='system' AND template_key='subscription.account_closed' AND template_type='email'
);

