notice that your rent for **{{propertyLabel}}** is {{amountOwedDisplay}} overdue, {{daysOverdue}} days past the due date. Please arrange payment by {{deadlineDate}}."},{"type":"dataBox","rows":[{"label":"Property","value":"{{propertyLabel}}"},{"label":"Amount outstanding","value":"{{amountOwedDisplay}}"},{"label":"Days overdue","value":"{{daysOverdue}}"}]},{"type":"paragraph","text":"If you have already processed payment, please confirm by replying to this email. If you are experiencing difficulties, please contact us to discuss a payment arrangement."},{"type":"paragraph","text":"If you have already made payment, please disregard this message. Contact {{branding.orgEmail}} to confirm allocation."},{"type":"signoff","text":"Kind regards,\n{{senderName}}"}],"firm":[{"type":"salutation","text":"{{recipient.salutation}}"},{"type":"heading","text":"NOTICE: Rent overdue"},{"type":"paragraph","text":"Your rental account for **{{propertyLabel}}** reflects an overdue balance of {{amountOwedDisplay}} ({{daysOverdue}} days past due). Immediate payment is required."},{"type":"dataBox","rows":[{"label":"Property","value":"{{propertyLabel}}"},{"label":"Amount outstanding","value":"{{amountOwedDisplay}}"},{"label":"Days overdue","value":"{{daysOverdue}}"}]},{"type":"paragraph","text":"Failure to pay or contact us by {{deadlineDate}} will result in formal escalation. Payment plans are available but must be arranged by {{deadlineDate}}."},{"type":"paragraph","text":"If you have already made payment, please disregard this message. Contact {{branding.orgEmail}} to confirm allocation."},{"type":"signoff","text":"Kind regards,\n{{senderName}}"}]}'::jsonb
